const STUDY_MATERIALS = [
  // WEEK 1: History & Studying Cognition
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Cognitive Psychology (Definition)", expl: "The study of mental processes, representations, and activities, focusing on how knowledge is acquired, stored, dealt with, and manipulated." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Empiricism (John Locke, Aristotle)", expl: "Argues that knowledge comes entirely from an individual's experiences. Proposed the 'blank slate' (tabula rasa) concept where associations of mental images form the contents of the mind." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Nativism (Plato, Rene Descartes)", expl: "Argues that knowledge is innate, biologically determined, and comes from heredity. Plato used the analogy of memories as writings on a 'wax tablet'." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Structuralism (William Wundt, 1879)", expl: "The first scientific school of psychology (Leipzig, Germany). Proposed that mental activity can be broken down into basic elements (sensations and feelings) akin to physical sciences." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Functionalism (William James)", expl: "Direct reaction to Structuralism. Focused on the functions and purpose of specific mental activities in real-life contexts, drawing heavily from Darwinian evolution." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Gestalt School", expl: "Proposed that the whole is always more than the sum of its parts. Breaking a mental experience (like a movie or a song) into basic elements destroys the combined, unified experience." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Behaviorism (Watson, Skinner, Clark Hull)", expl: "Rejected the study of unobservable hidden mental states. Strictly studied observable stimulus, response, and consequences. Failed because it couldn't explain complex behaviors like language." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "The Cognitive Revolution", expl: "Started with the advent of computers. Researchers (Herbert Simon, Alan Newell, Noam Chomsky) modeled the working of the human mind as an information-processing system." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Mind-Brain Analogy Limitation", expl: "While computers are hardware running uniform software, the mind (software) and brain (hardware) are biologically unified. You cannot transport a human mind to different hardware." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Structure-Process Tradeoff", expl: "The difficulty in distinguishing whether longer mental processing time is due to a complex serial process (more processes) or a complex brain structure managing parallel processes." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Information Processing Approach", expl: "Views cognition as information passing through systems. Stages: Environment → Attention (Filter) → Short-term Memory (Rehearsal) → Long-term Memory (Categorization via schemas/trees)." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Connectionism (Parallel Distributed Processing)", expl: "Argues that small neuronal units connect to give rise to mental experiences. Instead of large sequential systems, computation occurs via excitatory/inhibitory weights propagating across a network." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Evolutionary Approach", expl: "Proposes that specialized cognitive abilities (like 3D perception and language) are biologically ingrained through natural selection and evolutionary heritage." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Ecological Approach", expl: "Asserts that cognitive activities operate in specific cultural contexts. For example, processing differs widely between individualistic (Western) and collectivist (Asian) cultures." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Dissociation (Brain Studies)", expl: "Occurs when a variable/task affects one mental process or brain area but leaves another completely unaffected (e.g., loading visual working memory does not disrupt auditory memory)." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Association (Brain Studies)", expl: "Occurs when two seemingly different cognitive tasks or inputs consistently activate the exact same shared brain region or representational structure." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Behavioral Methods", expl: "Measure observable phenomena like Accuracy (percentage correct), Response Time (processing speed), Judgments (rating scales), and Verbal Protocol (speaking thoughts aloud)." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Ceiling & Floor Effects", expl: "Limitations in behavioral accuracy methods: Tasks are incredibly too easy (ceiling) or impossibly too hard (floor), preventing accurate measurement of cognitive variations." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Speed-Accuracy Tradeoff", expl: "A core behavioral limitation: As participants try to be more accurate, their response time slows down, creating an inverse relationship." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Experimental Expectancy Effect", expl: "When participants subconsciously adjust their behavioral responses to match what they believe the experimenter wants or expects from the task." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Correlational Neural Methods", expl: "Techniques (EEG, PET, fMRI) that correlate mental events with localized brain activity. However, correlation does not prove that an area causes the mental event." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "EEG (Electroencephalogram) & ERPs", expl: "Records weak electrical scalp potentials. Detects Event-Related Potentials (ERPs) like p300 (novelty). Excellent temporal (millisecond) resolution, but extremely poor spatial resolution." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "MEG (Magnetoencephalography)", expl: "Captures magnetic fields generated by neurons. Offers excellent temporal AND spatial resolution with low invasiveness, but the purchase/operational costs are massive." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "PET (Positron Emission Tomography)", expl: "Injects radioactive isotope (e.g., Oxygen-15). Measures blood flow to activated areas. Good spatial resolution, but very poor temporal resolution (takes 40s) and high invasiveness." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "MRI & fMRI", expl: "Uses strong electromagnets to measure BOLD (Blood Oxygen Level Dependent) signals. Superior spatial (millimeter) resolution, moderate temporal resolution, and zero invasiveness." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Optical Imaging", expl: "Shines near-infrared lasers into the brain; reflected light determines blood flow. Safe and low cost, but restricted to surface cortical activities with poor resolution." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Causal Neural Methods", expl: "Methods that temporarily or permanently disrupt a brain region (lesions, TMS, specific drugs) to establish if that region is strictly necessary for a cognitive task." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "TMS (Transcranial Magnetic Stimulation)", expl: "Employs an external magnetic coil to temporarily inhibit or excite targeted cortical neurons (e.g., rTMS causing temporary virtual lesions without permanent damage)." },
  { week: 1, topic: "History", topicIcon: "<i data-lucide='scroll'></i>", q: "Process vs. Neural Network Models", expl: "Process models use sequence flowcharts (input -> scan -> output) to outline logical steps. Neural network models explicitly simulate brain states via nodes, hidden layers, and interconnected weights." },

  // WEEK 2: Perception
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Sensation vs. Perception", expl: "Sensation is the raw, physiological intake of physical stimuli (e.g., light waves to retina). Perception is the psychological interpretation of that stimuli, converting it into a meaningful percept." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Distal vs. Proximal Stimulus", expl: "The distal stimulus is the actual object out in the real world. The proximal stimulus is the inverted, 2D sensory image that falls directly onto the retina." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Size Constancy", expl: "The percept remains stable even when the proximal stimulus drastically changes. For example, your hand's size on the retina grows as it moves closer, but you still perceive the hand as the same size." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Gestalt: Figure-Ground Perception", expl: "The most fundamental step in Gestalt perception. We instantly divide any visual field into a distinct 'figure' that commands attention and a 'background' that is ignored (e.g., reversible faces/vase illusion)." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Gestalt: Law of Pragnanz", expl: "The overarching Gestalt principle meaning 'good figure'. We automatically perceive the simplest, most stable, and most regular interpretation of a visual scene possible." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Gestalt Principles of Organization", expl: "Five specific rules governing grouping: Proximity (near items grouped), Similarity (like items grouped), Good Continuation (curved contours grouped), Closure (filling gaps), and Common Fate (moving together grouped)." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Bottom-Up Processing", expl: "A strictly data-driven procedure where perception is built starting purely from specific raw stimulus features up to a mental generalization, heavily reliant on sensory input without prior expectation." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Template Matching Model", expl: "A simplistic bottom-up theory asserting the brain contains exact stencils/templates for objects. Flawed because it cannot explain how we read sloppy handwriting or recognize entirely novel versions of objects." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Feature Analysis Model", expl: "A robust bottom-up theory. We perceive by breaking an object down into fundamental traits (e.g., edges, curves). Supported biologically by 'edge detectors' and 'bug detectors' found in frog specific retinal cells." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Biederman's Geons", expl: "A feature analysis theory proposing 36 fundamental 3D geometric shapes ('geons', like cylinders, blocks). Biederman argued any object can be constructed simply by rearranging these 36 geon building blocks." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Selfridge's Pandemonium Model", expl: "A feature analysis model using 'demons'. Feature demons shout when they see specific lines/curves, passing to letter demons, and finally to a decision demon. Highlights how basic inputs aggregate sequentially without feedback." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Prototype Matching Model", expl: "An updated bottom-up theory. We form an idealized abstract 'prototype' based on various object exposures. New stimuli are judged not by exact stencil matching, but by how closely they resemble the flexible prototype." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Top-Down Processing", expl: "A conceptually-driven procedure. Processing is heavily influenced by the observer's expectations, prior knowledge, and the context in which the object appears. Also called 'Theory Driven'." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Perceptual Learning", expl: "A top-down phenomenon where visual discrimination strictly improves with practice and exposure. (e.g., Gibson's coil experiment, where subjects gradually learned to distinguish subtle coil differences over time)." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Change Blindness", expl: "The failure to detect major visual changes in a scene because our top-down expectations dictate what should be there. We process the 'gist' of the scene rather than storing every pixel of information." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Word Superiority Effect", expl: "A classic top-down effect. Letters are significantly easier to perceive, identify, and recall when presented in the context of a real word compared to being presented in isolation or in a non-word string." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "David Marr's Computational Model", expl: "An elegant synthesis. Three stages: The bottom-up Primal Sketch (2D light/dark) and 2.5D Sketch (shading/depth), concluding with the top-down 3D Representation which incorporates memory and context." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Gibson's Direct Perception", expl: "An ecological theory arguing top-down/bottom-up aren't needed. The environment contains incredibly rich information inherently. Observers simply extract meaning without mental construction (supported by his point-light walker actor studies)." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Affordances (Gibson)", expl: "In Direct Perception, objects overtly dictate their function. A chair provides the affordance of sitting; a round knob affords turning. The perceptual environment tells the observer strictly what behaviors are allowable." },
  { week: 2, topic: "Perception", topicIcon: "<i data-lucide='eye'></i>", q: "Neisser's Perceptual Cycle", expl: "Harmonized constructivist and direct perception views. Hypothesizes that cognitive schemas dictate where we look in the environment, the environment gives us direct information, which in turn modifies our cognitive schemas." },

  // WEEK 3: Attention
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Selective Attention & Dichotic Listening",
    expl: "Cherry (1953) had participants 'shadow' one ear's message. Result: They could notice physical changes in the unattended ear (gender of speaker) but missed semantic content (language changes, specific words)." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Broadbent's Early Filter Theory (1958)",
    expl: "Postulated a strict bottleneck filter operating purely on physical characteristics (pitch, location). Information on the rejected channel is completely lost before processing for meaning." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Triesman's Attenuation Model",
    expl: "Addressed flaws in Broadbent's model (e.g., the Cocktail Party Effect where you hear your name). The filter does not block entirely; it 'turns down' unattended channels. Highly salient words have a low threshold and can break through." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Automatic vs. Controlled Processing",
    expl: "Automatic processing is fast, inflexible, requires no conscious intention, and consumes negligible resources. Controlled processing is slow, deliberate, sequential, and heavily taxes cognitive load." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "The Stroop Effect",
    expl: "Demonstrates automaticity overriding controlled control: naming ink color is significantly slower when the word spells out a conflicting color name, because reading the text is highly automatic." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Attention Definition & Function",
    expl: "A limited cognitive resource equivalent to mental concentration. It acts as a sieve/filter that decides whether incoming stimuli are fully perceived and processed or ignored." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Shadowing Paradigm",
    expl: "An experimental technique closely associated with dichotic listening tasks where a participant is asked to immediately repeat aloud an attended auditory message while ignoring a concurrent message." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Cocktail Party Effect (Moray, 1959)",
    expl: "Demonstrated that highly salient personal information (like one's name or distress words) can capture attention from an unattended channel, challenging strict early-selection filter theories." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Late Selection Theory (Deutsch & Norman)",
    expl: "Argues that all messages are processed to the semantic (meaning) level before any filtration occurs. The bottleneck happens late and is based on alertness and message complexity." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Multimodal Theory of Attention",
    expl: "Johnston & Heinz (1978) proposed attention is flexible. Filtration can happen early (sensory), later (semantic), or deep (combined), depending on the requirements of differentiating the stimuli." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Capacity Model of Attention (Kahneman)",
    expl: "Views attention as a limited-capacity resource allocation model that distributes mental effort based on level of arousal, available capacity, and momentary allocation policies." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Schema Theory of Attention (Neisser)",
    expl: "Argues attention does not filter 'out' unwanted messages; instead, we simply never perceive them in the first place (like unpicked apples). Unattended information simply remains outside the cognitive system." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Inattentional Blindness",
    expl: "The psychological phenomenon where an individual fails to perceive a highly visible, unexpected stimulus in plain sight because their attentional focus is fully engaged on another demanding task." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Criteria for Automaticity",
    expl: "Posner & Snyder (1975) defined a process as automatic if it: 1) occurs without intention, 2) occurs without conscious awareness, and 3) does not interfere with other concurrent mental activities." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Varied vs. Consistent Mapping",
    expl: "Schneider & Shiffrin (1977) found that searching for changing targets (varied mapping) requires slow controlled processing. Searching for consistent categorical targets across trials becomes a fast automatic process." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Feature Integration Theory (Treisman)",
    expl: "Perception involves two stages: a pre-attentive stage where isolated physical features are registered rapidly in parallel, and an attentive stage where attention acts as the 'glue' to bind features into coherent objects." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Illusory Correlation (Feature Conjunction Error)",
    expl: "A perceptual error occurring under high attentional load or rapid displays, where features from different objects (e.g. color of one, shape of another) are incorrectly glued together by the visual system." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Attentional Capture ('Pop-out')",
    expl: "A bottom-up, involuntary shift of attention driven entirely by highly salient stimulus properties in the environment that stand out against the background distractors." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Automization Hypothesis",
    expl: "Gordon Logan argued attention is exclusively required during the initial practice/learning phase of a task. Once fully learned, the task shifts to automatic and bypasses the attentional network." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Psychological Refractory Period (PRP)",
    expl: "A reliable delay in the response to a second stimulus when presented in rapid succession to a first stimulus. It demonstrates a central cognitive bottleneck strictly at the response-selection stage." },
  { week: 3, topic: "Attention", topicIcon: "<i data-lucide='target'></i>", q: "Attentional Spotlight Metaphor",
    expl: "Attention works like a theater spotlight where the center is highly focused but boundaries are fuzzy, allowing partial processing of peripheral information." },

  // WEEK 4: Memory Introduction & Short-Term Memory
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Atkinson-Shiffrin Modal Model (1968)",
    expl: "The classic box model with three stores: Sensory Register (high capacity, very brief), Short-Term Memory (limited capacity, brief duration), and Long-Term Memory (theoretically infinite)." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "STM Capacity & Chunking",
    expl: "George Miller determined STM capacity to be 'the magical number 7, plus or minus 2' items. We bypass this via 'chunking', grouping raw items into meaningful, larger cognitive units." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Baddeley's Working Memory Model",
    expl: "Replaced the unitary STM structure. It’s an active manipulation space, not just a passive store. Controlled by a Central Executive, which manages two slave systems: the Phonological Loop and the Visuospatial Sketchpad." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Historical Memory Metaphors",
    expl: "Philosophers and scientists map memory onto contemporary technology: Plato's wax tablet, Middle-age caves/cabinets, 1950s telephone switchboards, and modern computer systems (input/throughput/output)." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Serial Position Curve (Free Recall)",
    expl: "Items at the beginning (Primacy effect - due to rehearsal entering LTM) and end (Recency effect - due to items remaining in STM) of a list are remembered better than middle items." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Sensory Memory",
    expl: "The earliest stage of the modal model. It captures massive amounts of modality-specific physical information but holds it for a very brief duration in highly unprocessed formats." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Iconic Memory & Sperling's Partial Report",
    expl: "Visual sensory memory (the icon) lasts 150-200ms. Sperling proved this by replacing a whole-report method with a partial-report cued by tone, showing the icon holds near perfect detail before rapidly fading." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Echoic Memory",
    expl: "Auditory sensory memory (the echo) discovered by Neisser. It has a larger functional readout capacity and longer retention duration than iconic memory because spoken language unfolds sequentially over time." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Acoustic Coding in STM",
    expl: "Conrad (1964) proved that STM primarily utilizes acoustic formats (subvocal rehearsal); participants made auditory confusion errors (e.g. confusing 'C' for 'T') even when items were presented purely visually." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Brown-Peterson Task & Decay Theory",
    expl: "Showed participants trigrams followed by a backward-counting task to prevent rehearsal. Recall dropped significantly over 18 seconds, interpreted initially as proof that STM spontaneously 'decays' without use." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Waugh & Norman Probe-Digit Task",
    expl: "Challenged the pure decay theory. They proved that forgetting in STM is largely due to 'Proactive Interference' (older memories displacing new ones depending on the number of overlapping items), not strictly time decay." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Release from Proactive Interference",
    expl: "Wickens (1963) found that when the categorical type of items changes (e.g. switching from memorizing letters to digits) previous interference drops and recall performance resurges." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Sternberg Search Task (STM Retrieval)",
    expl: "Sternberg demonstrated that searching for an item within STM utilizes a 'Serial Exhaustive Search', where items are searched one at a time, and the search continues completely even after a match is found." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Components of Working Memory",
    expl: "The Central Executive manages resources, reasoning, and language (like a boss/manager). It shuttles data to the Phonological Loop (verbal rehearsal), Visuospatial Sketchpad (visual cache), and Episodic Buffer (LTM interface)." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Stimulus Independent Thought (SIT)",
    expl: "Daydreaming (SIT) requires Central Executive resources. It is disrupted by complex active reasoning tasks (like verifying sentences) but remains largely unaffected by simple, deeply routine/automatic tasks." },
  { week: 4, topic: "Memory & Working Memory", topicIcon: "<i data-lucide='brain'></i>", q: "Know vs. Remember Debate",
    expl: "A core recognition memory debate distinguishing between explicitly 'remembering' the context of an event versus simply 'knowing' or feeling familiar with it without retaining source memory." },

  // WEEK 5: Long-Term Memory Encoding
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "Levels of Processing Theory (Craik & Lockhart)",
    expl: "Challenged the modal model by arguing memory strength relies on processing depth, not separate boxes. Deep (semantic) processing yields stronger, longer-lasting memories than shallow (structural/orthographic) encoding." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "Elaborative vs. Maintenance Rehearsal",
    expl: "Maintenance rehearsal (simple rote repetition) only holds items in STM temporarily. Elaborative rehearsal (connecting new info to existing semantic networks) successfully facilitates transfer into LTM." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "Encoding Specificity Principle",
    expl: "Tulving showed that memory is improved when conditions at retrieval match conditions at encoding. E.g., learning underwater means testing better underwater (context-dependent memory)." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "LTM Capacity & Compression",
    expl: "LTM has a virtually infinite capacity (estimated up to 10^13 synapses or 10^20 neural transmission bits). It utilizes an advanced compression system to store essential features rather than exact physical replicas." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "Format of LTM Coding",
    expl: "Unlike STM's acoustic format, LTM encodes information primarily in a semantic (meaning-based) format. Baddeley showed that semantically similar words cause later retrieval confusion, whereas acoustic similarity has little effect." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "Declarative vs. Procedural Memory",
    expl: "Declarative (Explicit) memory is consciously recalled (e.g., facts and events). Procedural (Implicit) memory is unconscious and action-based (e.g., motor skills, habits, classical conditioning, and priming)." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "Semantic vs. Episodic Memory",
    expl: "Both are Declarative. Semantic memory acts like a newspaper (static facts and general world knowledge). Episodic memory acts like a television show (dynamic, autobiographical events involving mental time travel)." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "Forgetting: Encoding Failure Theory",
    expl: "Forgetting occurs because the information never actually successfully transferred from short-term memory into long-term memory in the first place, often due to lack of attention or rehearsal." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "Forgetting: Decay Theory",
    expl: "Argues that if memory traces are unused over long periods, normal metabolic brain functions gradually erode those synaptic connections. Not fully accepted as the sole reason for forgetting." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "Forgetting: Retrieval Cue Failure",
    expl: "The memory exists in LTM, but the required 'key' or cue to fetch it is missing. This explains the 'tip-of-the-tongue' phenomenon, where partial details are known but the target word is blocked." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "State-Dependent Memory",
    expl: "A facet of the Encoding Specificity Principle. Memory improves if learners are in the same internal physiological or emotional state (e.g., mood, sobriety level) during testing as they were during encoding." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "Spacing Effect",
    expl: "Studying across multiple shorter sessions (spaced practice) yields drastically better retention than cramming (massed practice) because it creates higher encoding variability and provides multiple unique retrieval cues." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "Reconstructive Nature of Memory",
    expl: "Memory is not a static video recording. It reconstructs events heavily using schemas (mental frameworks for objects) and scripts (frameworks for event sequences), leading to gist-based recall and frequent distortions." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "Loftus Misinformation Effect",
    expl: "Eyewitness memories can be rewritten by leading questions. Loftus demonstrated that asking how fast cars 'smashed' versus 'contacted' caused viewers to actively reconstruct higher speed estimates and falsely recall facts." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "Flashbulb Memories",
    expl: "Highly vivid, detailed memory 'snapshots' tied to shocking, highly emotional events (e.g., 9/11). Despite people's extreme confidence in them, they are actually highly susceptible to inaccuracy and distortion over time." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "DRM Paradigm (False Memories)",
    expl: "The Deese-Roediger-McDermott paradigm reliably creates false memories. Presenting a list of semantically related words (like dark, pillow, nap) causes 80% of people to falsely recall the unpresented theme word 'sleep'." },
  { week: 5, topic: "Long-Term Memory", topicIcon: "<i data-lucide='book-open'></i>", q: "Anterograde vs. Retrograde Amnesia",
    expl: "Anterograde is the inability to encode new declarative memories after the injury point (like patient H.M.). Retrograde amnesia is the loss of old declarative memories that were stored before the injury point." },

  // WEEK 6: Semantic Memory Basics
  { week: 6, topic: "Semantic Memory", topicIcon: "<i data-lucide='network'></i>", q: "Episodic vs Semantic Memory",
    expl: "Episodic memory involves mental time travel and personal experience ('remembering when'). Semantic memory is an organized database of general world knowledge, facts, and concepts ('remembering what'). Biological evidence (blood flow) shows they use different brain regions." },
  { week: 6, topic: "Semantic Memory", topicIcon: "<i data-lucide='network'></i>", q: "Bookshelf Metaphor",
    expl: "A classic analogy suggesting semantic memory organizes facts like a library's calling catalog, where knowledge is indexed and cross-referenced based on initial letters or broad categories." },
  { week: 6, topic: "Semantic Memory Models", topicIcon: "<i data-lucide='git-merge'></i>", q: "Hierarchical Semantic Network Model (Collins & Quillian)",
    expl: "Concepts are arranged in hierarchical nodes connected by pointers (e.g., Animal -> Bird -> Canary). It relies on 'Cognitive Economy', where shared properties are stored only at the highest applicable superordinate node to save space." },
  { week: 6, topic: "Semantic Memory Models", topicIcon: "<i data-lucide='git-merge'></i>", q: "Criticisms of Hierarchical Model",
    expl: "It fails to explain the 'Typicality Effect' (Robin is verified faster than Ostrich, though both are technically 1 node away from Bird) and hierarchical violations (Pig is verified as an Animal faster than as a Mammal)." },
  { week: 6, topic: "Semantic Memory Models", topicIcon: "<i data-lucide='git-merge'></i>", q: "Feature Comparison Model (Smith, Shoben, Rips)",
    expl: "Argues concepts are stored as lists of features categorized into 'Defining' (absolute requirements, e.g., a bird has feathers) and 'Characteristic' (common but not strictly necessary, e.g., a bird can fly)." },
  { week: 6, topic: "Semantic Memory Models", topicIcon: "<i data-lucide='git-merge'></i>", q: "2-Stage Verification in Feature Model",
    expl: "Stage 1 compares all features (defining + characteristic) for a quick true/false decision. If the feature overlap is intermediate/ambiguous, Stage 2 kicks in to specifically evaluate only the 'defining' features." },
  { week: 6, topic: "Semantic Memory Models", topicIcon: "<i data-lucide='git-merge'></i>", q: "Spreading Activation Model (Collins & Loftus)",
    expl: "Drops rigid hierarchy. Concepts are an interconnected web with varying pointer weights representing semantic similarity. Re-energizing a node spreads activation outward, with the signal decaying over distance." },
  { week: 6, topic: "Semantic Memory Models", topicIcon: "<i data-lucide='git-merge'></i>", q: "ACT-R Model (John Anderson)",
    expl: "A computational framework splitting memory into: Declarative Memory (spatial/abstract nodes), Working Memory (highly active nodes currently in use), and Procedural Memory (If-Then production rules to achieve goal states)." },
  { week: 6, topic: "Semantic Memory Models", topicIcon: "<i data-lucide='git-merge'></i>", q: "Connectionist Model (Neural Networks)",
    expl: "Knowledge is not stored as discrete concepts, but as distributed patterns of activation across input, hidden, and output units. The network 'learns' by biologically adjusting connection weights across thousands of trials." },
  { week: 6, topic: "Schemas & Scripts", topicIcon: "<i data-lucide='layout-template'></i>", q: "Schemas & Reconstructive Memory (Bartlett)",
    expl: "Using the 'War of the Ghosts' story, Bartlett showed memory relies on schemas—large organizational frameworks of knowledge that mix fixed facts and variable default assumptions, heavily simplifying and altering recalled events." },
  { week: 6, topic: "Schemas & Scripts", topicIcon: "<i data-lucide='layout-template'></i>", q: "Scripts",
    expl: "Scripts are a specialized chronological type of schema applied to routine, sequenced events. For instance, the 'Restaurant Script' dictates the expected, ordered procedures: be seated, read menu, order, eat, pay, and leave." },

  // WEEK 7: Concepts & Categories
  { week: 7, topic: "Concepts & Categories", topicIcon: "<i data-lucide='folder-open'></i>", q: "Concept vs. Category",
    expl: "A 'Concept' is a mental representation (a mental bucket) of accumulated knowledge about an object, event, or pattern. 'Categorization' is the active process of sorting new instances into these buckets based on features." },
  { week: 7, topic: "Concepts & Categories", topicIcon: "<i data-lucide='folder-open'></i>", q: "Classical View of Concepts",
    expl: "Argues all instances of a concept share fundamental features that are 'individually necessary' and 'collectively sufficient'. Implies clear-cut boundaries where every object is an equally good member." },
  { week: 7, topic: "Concepts & Categories", topicIcon: "<i data-lucide='folder-open'></i>", q: "Prototype View",
    expl: "Argues we classify items by comparing them to a mental average or idealized representation (a prototype) created from all observed instances. Instead of rigid boundaries, categories have 'family resemblance'." },
  { week: 7, topic: "Concepts & Categories", topicIcon: "<i data-lucide='folder-open'></i>", q: "Typicality Effect",
    expl: "A major critique of the Classical View. Some members are judged as 'better' fits for a category than others (e.g., Robin is a better 'bird' than an Ostrich) due to varying distances from the prototype." },
  { week: 7, topic: "Concepts & Categories", topicIcon: "<i data-lucide='folder-open'></i>", q: "Basic Level of Categorization",
    expl: "The most psychologically fundamental level of conceptual organization (e.g., 'Dog') which balances information. Above it is superordinate (Animal), and below it is subordinate (Pomeranian)." },
  { week: 7, topic: "Concepts & Categories", topicIcon: "<i data-lucide='folder-open'></i>", q: "Exemplar View",
    expl: "Denies that we form abstract mental summaries. Instead, we categorize new instances by comparing them directly against actual, specific memory traces of existing examples we've encountered before." },
  { week: 7, topic: "Concepts & Categories", topicIcon: "<i data-lucide='folder-open'></i>", q: "Schemata View",
    expl: "A hybrid approach positing that concepts are large frameworks with 'roles', 'slots', and 'variables'. Abstractions form the framework, but actual instances dictate the slots." },
  { week: 7, topic: "Concepts & Categories", topicIcon: "<i data-lucide='folder-open'></i>", q: "Knowledge-Based (Explanation-Based) View",
    expl: "Categorization based not on physical similarity, but on meaningful relationships, human goals, and theories about the world. E.g., 'Things to save in a fire' groups a child, money, and laptop together." },
  { week: 7, topic: "Concepts & Categories", topicIcon: "<i data-lucide='folder-open'></i>", q: "Concept Attainment Strategies (Bruner)",
    expl: "Using variation cards, Bruner found three strategies for attaining concepts: Simultaneous Scanning (testing all hypotheses), Successive Scanning (testing one by one), and Conservative Focusing (comparing to a positive base instance)." },
  { week: 7, topic: "Concepts & Categories", topicIcon: "<i data-lucide='folder-open'></i>", q: "Implicit Concept Learning",
    expl: "Brooks (1978) found people often categorize artificial grammar strings or complex patterns better when relying on non-analytical implicit learning, rather than explicitly deducing complex rules." },

  // WEEK 8: Visual Memory
  { week: 8, topic: "Visual Memory", topicIcon: "<i data-lucide='image'></i>", q: "Method of Loci",
    expl: "A mnemonic technique where items to be remembered are mentally placed in specific physical locations of a highly familiar spatial environment (like your house)." },
  { week: 8, topic: "Visual Memory", topicIcon: "<i data-lucide='image'></i>", q: "Dual Coding Hypothesis (Paivio)",
    expl: "LTM stores two distinct codes: verbal/linguistic codes for abstract meaning, and visual imagery codes for physical representations. Concrete words get both, making retrieval far superior." },
  { week: 8, topic: "Visual Memory", topicIcon: "<i data-lucide='image'></i>", q: "Relational Organizational Hypothesis (Bower)",
    expl: "Argues imagery improves memory not by being intrinsically 'richer', but by forcing the creator to forge numerous associative hooks and relational meaning between the items." },
  { week: 8, topic: "Visual Memory", topicIcon: "<i data-lucide='image'></i>", q: "Mental Rotation (Shepard & Metzler)",
    expl: "Found that people mentally rotate entire 3D objects continuously. The reaction time required to verify a rotated object is directly proportional to the actual angle of rotation." },
  { week: 8, topic: "Visual Memory", topicIcon: "<i data-lucide='image'></i>", q: "Implicit Coding (Finke)",
    expl: "One of Finke's properties: mental images can be scanned to extract physical information that was not intentionally or explicitly memorized originally (e.g., counting window panes in a childhood home)." },
  { week: 8, topic: "Visual Memory", topicIcon: "<i data-lucide='image'></i>", q: "Equivalences of Visual Imagery (Finke)",
    expl: "Mental images mimic reality across domains: Perceptual (same neural activation), Spatial (traveling mental maps takes time proportional to distance), Transformational (follows physics laws), and Structural (complexity adds time)." },
  { week: 8, topic: "Visual Memory", topicIcon: "<i data-lucide='image'></i>", q: "Propositional Theory (Pylyshyn)",
    expl: "A critique arguing visual images are merely 'epiphenomena' (a useless byproduct like a flashing computer light). It posits that all LTM storage is abstract, language-like relational networks (e.g., ON(book, table))." },
  { week: 8, topic: "Visual Memory", topicIcon: "<i data-lucide='image'></i>", q: "Demand Characteristics / Tacit Knowledge",
    expl: "A criticism arguing imagery tasks are 'cognitively penetrable', meaning subjects intuitively know how long a visual task SHOULD take physically, and subconsciously adjust their reaction times to match those expectations without truly 'imagining'." },

  // WEEK 9: Human Language Skills
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Properties of Natural Language",
    expl: "True languages must be: 1. Regular (governed by grammar) 2. Productive (can generate infinite new ideas) 3. Arbitrary (no physical resemblance between word and object) 4. Discrete (easily broken into distinct parts)." },
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Phonemes vs. Morphemes",
    expl: "Phonemes: The smallest units of speech sound forming the language (e.g., 'a', 'p'). Morphemes: The smallest units of meaning, comprising combinations of phonemes (e.g., words, roots, 'ed' suffix, 'un' prefix)." },
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Syntax, Semantics, & Pragmatics",
    expl: "Syntax = Grammatical structure and word arrangement. Semantics = The meaning derived from the sentence. Pragmatics = The social context, conversational flow, and etiquette influencing interpretation." },
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Consonants vs. Vowels",
    expl: "Vowels are produced without obstructing airflow through the mouth. Consonants are produced by obstructing airflow, relying on Place, Manner of articulation, and Voicing (vocal cord vibration)." },
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Continuous Nature of Speech Perception",
    expl: "Unlike text read word-by-word, spectrograms show that auditory speech is produced as a continuous stream where words visually blend together without clear pauses separating them." },
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Phonemic Restoration Effect (Warren)",
    expl: "When a phoneme (like the 's' in legislature) is replaced by a cough, 95% of people report hearing the full word cleanly and cannot pinpoint the cough's location, proving we implicitly use context to fill gaps." },
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Categorical Perception",
    expl: "Our speech systems rapidly perceive and compress the chaotic continuous auditory stream of speech by implicitly forcing acoustically variant sounds into fixed pre-existing categories." },
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Garden-Path Sentences & Ambiguity",
    expl: "Sentences like 'The horse raced past the barn fell' naturally mislead the reader's expectation early on. When resolving ambiguous words, all meanings activate for about 3 syllables before context eliminates the wrong ones." },
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Speech Production Errors (Garrett)",
    expl: "Substitutions in speaking usually reflect either Meaning relations (swapping 'walk' for 'run') or Form relations (swapping 'mushroom' for 'mustache' because they sound/look similar)." },
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Eye-Tracking Text Comprehension",
    expl: "Reading involves short Eye Fixations (to extract word meaning) and rapid Jumps. The longer, rarer, or more ambiguous a word is, the longer the fixation required." },
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Given-New Strategy (Haviland & Clark)",
    expl: "Listeners divide incoming sentences into established 'Given' info and unfamiliar 'New' info. Comprehension is fastest when the 'Given' info easily attaches to memory of the preceding sentences." },
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Story Grammars",
    expl: "Similar to cognitive scripts, people expect cohesive texts to follow a 'grammar' containing predictable slots (Protagonist, Setting, Plot, Conflict, Resolution) allowing them to implicitly fill in unstated story gaps." },
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Grice's Maxims of Conversation",
    expl: "Social conversation rules require: Quantity (right amount of info), Quality (truthful/meaningful), Relation (relevant connection), and Manner (polite, unambiguous execution)." },
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Searle's Speech Act Theory",
    expl: "Categorizes what utterances demand of listeners: Assertives (beliefs), Directives (commands), Commissives (promises), Expressives (emotions), and Declaratives (the words enact the action itself)." },
  { week: 9, topic: "Human Language Skills", topicIcon: "<i data-lucide='message-square'></i>", q: "Modularity vs. Whorfian Hypothesis",
    expl: "Modularity (Fodor): Language processing happens in encapsulated domains independent of other cognitive beliefs. Whorfian Hypothesis: Language heavily integrates with cognition and ultimately shapes how we perceive reality." },

  // WEEK 10: Thought Processes & Problem Solving
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Four Elements of a Problem",
    expl: "Every problem consists of 1. An Initial State, 2. A Goal State, 3. Rules (what is allowed constraints), and 4. Obstacles (hindrances that must be navigated)." },
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Well-defined vs. Ill-defined Problems",
    expl: "Well-defined problems have clear starting points, endpoints, and structured constraints (e.g., getting a driver's license). Ill-defined problems are fuzzy and abstract with unclear boundaries (e.g., trying to become a politician)." },
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Mayer's 5 Problem Types",
    expl: "1. Transformational (navigating to goal), 2. Arrangement (reordering elements), 3. Induction (finding a pattern rule), 4. Deduction (verifying conclusions from premises), 5. Divergent (generating multiple solutions)." },
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Problem Representation",
    expl: "The crucial first step of encoding a problem to establish the initial boundary conditions. Failure to correctly mentally represent the problem invariably leads to failure in solving it." },
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Rigidity & Mental Set",
    expl: "A hindrance where solvers depend too rigidly on past habits or standard operating procedures, applying old problem-solving logic to a new problem where it acts as a mental block." },
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Functional Fixedness",
    expl: "A cognitive bias limiting a person to use an object only in the way it is traditionally used (e.g., seeing a set of pliers only as a wrench, and failing to use it as a pendulum weight)." },
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Stereotype Threat in Problem Solving",
    expl: "Anxious misrepresentation where individuals belong to a negatively stereotyped group and underperform due to anxiety confirming the stereotype, blocking logical realization." },
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Algorithms vs. Heuristics",
    expl: "Algorithms: Step-by-step procedures mathematically guaranteeing a correct solution but are tedious. Heuristics: Mental shortcuts or 'rules of thumb' that bypass algorithms for faster, but error-prone, results." },
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Means-Ends Analysis (GPS)",
    expl: "Used by the General Problem Solver (Newell & Simon). The solver decomposes a massive problem into sequential sub-goals, systematically bridging the gap between the initial and goal states." },
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Analogous Problem Solving",
    expl: "Extracting a solution from a structurally similar previous problem. Solvers must ignore distracting Surface Features to map the underlying Structural Features correctly." },
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Experts vs. Novices",
    expl: "Experts solve problems forward rather than backward, instinctively chunk structural domain knowledge, and can bypass working memory limits to read directly from long-term memory." },
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Wallas' 4 Stages of Creativity",
    expl: "Creative breakthroughs follow four stages: 1. Preparation (gathering info), 2. Incubation (unconscious inactive processing), 3. Illumination (sudden insight), 4. Verification (testing the solution focus)." },
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Insight vs. Non-Insight Problems",
    expl: "Non-insight problems: Solved by incremental, analytical algorithms (e.g., algebra). Insight problems: Solved suddenly ('Aha!') primarily by stripping away a paralyzing mistaken assumption." },
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Warmth Rating Problem (Metcalfe)",
    expl: "Testing metacognition: Solvers rate how 'warm' (close) they are to an answer. Non-insight problem warmth gradually increases. Insight problem warmth stays completely cold until a sudden spike at the end." },
  { week: 10, topic: "Thought Processes & Problem Solving", topicIcon: "<i data-lucide='puzzle'></i>", q: "Taxonomy of Creativity",
    expl: "Dictates that creative products are evaluated on two intersecting dimensions: Knowledge Domain (Cognitive vs. Emotional output) and Processing Mode (Spontaneous insight vs. Deliberate effort)." },

  // WEEK 11: Reasoning
  { week: 11, topic: "Reasoning", topicIcon: "<i data-lucide='scale'></i>", q: "Reasoning vs Judgment vs Decision Making",
    expl: "Reasoning evaluates premises to draw conclusions. Judgment takes those conclusions, combined with past beliefs, to make educated guesses under uncertainty. Decision Making involves taking action by choosing among the judgements." },
  { week: 11, topic: "Reasoning", topicIcon: "<i data-lucide='scale'></i>", q: "System 1 vs System 2 Reasoning",
    expl: "System 1 is fast, automatic, heuristic-based, and prone to emotional biases. System 2 is slow, analytical, cognitively demanding, and logical." },
  { week: 11, topic: "Reasoning", topicIcon: "<i data-lucide='scale'></i>", q: "Deductive Reasoning",
    expl: "Reasoning from General premises to Specific instances. In deductive logic, you evaluate the exact 'Validity' of the structure, not the real-world 'Truth' of the premise." },
  { week: 11, topic: "Reasoning", topicIcon: "<i data-lucide='scale'></i>", q: "Inductive Reasoning",
    expl: "Reasoning from Specific observations to a General conclusion. Inductive reasoning never reaches 100% logical certainty; it is evaluated entirely on the 'Strength' and probability of the argument." },
  { week: 11, topic: "Reasoning", topicIcon: "<i data-lucide='scale'></i>", q: "Belief Bias",
    expl: "A logical fallacy occurring in Syllogistic Deductive reasoning where people incorrectly inject real-world Truth to reject a perfectly 'Valid' logical structure just because their beliefs disagree with the premise." },
  { week: 11, topic: "Reasoning", topicIcon: "<i data-lucide='scale'></i>", q: "Conditional Reasoning Rules",
    expl: "In an 'If (Antecedent), Then (Consequent)' scenario, you can logically conclude truth only by 'Affirming the Antecedent' (Modus Ponens) or 'Denying the Consequent' (Modus Tollens)." },
  { week: 11, topic: "Reasoning", topicIcon: "<i data-lucide='scale'></i>", q: "Wason Selection Task",
    expl: "A classic logic test proving humans naturally seek out confirmatory evidence (Confirmation Bias) rather than rationally seeking out falsifying evidence (Denying the Consequent)." },
  { week: 11, topic: "Reasoning", topicIcon: "<i data-lucide='scale'></i>", q: "Typicality & Diversity Effects",
    expl: "In Inductive reasoning, generalizations are rated stronger if the given examples are highly 'typical' of the category, or if the examples cover a highly 'diverse' spread across the category." },
  { week: 11, topic: "Reasoning", topicIcon: "<i data-lucide='scale'></i>", q: "Availability Heuristic",
    expl: "A judgment fallacy where people estimate the actual statistical probability of an event primarily by how easily memories or dramatic recent examples come to mind (e.g. Media coverage creating plane-crash fears)." },
  { week: 11, topic: "Reasoning", topicIcon: "<i data-lucide='scale'></i>", q: "Representativeness Heuristic",
    expl: "A judgment fallacy where people force objects into mental categories just because they visually overlap with typical stereotypes, entirely ignoring statistical reality." },
  { week: 11, topic: "Reasoning", topicIcon: "<i data-lucide='scale'></i>", q: "Base Rate Fallacy",
    expl: "The error of completely ignoring the actual population statistics (base rate) when evaluating how likely it is someone belongs to a specific category, swayed instead by character descriptions." },
  { week: 11, topic: "Reasoning", topicIcon: "<i data-lucide='scale'></i>", q: "Conjunction Fallacy",
    expl: "A logical failure where people believe two specific co-occurring events are statistically MORE probable than one general event alone, violating the laws of independent probability." },
  { week: 11, topic: "Reasoning", topicIcon: "<i data-lucide='scale'></i>", q: "Hindsight Bias",
    expl: "The 'I knew it all along' phenomena where people incorrectly overestimate their ability to have perfectly predicted an event only *after* it occurred." },

  // WEEK 12: Decision Making
  { week: 12, topic: "Decision Making", topicIcon: "<i data-lucide='dice-5'></i>", q: "Decision Making Paradigm",
    expl: "The final step in higher-order cognition where one option is selected among alternatives generated by judgment. Generally conducted under conditions of uncertainty and risk." },
  { week: 12, topic: "Decision Making", topicIcon: "<i data-lucide='dice-5'></i>", q: "Threshold Approach of Choice",
    expl: "The probability of choosing an option dramatically increases the exact moment an associated desirable event crosses a minimum threshold of psychological 'certainty'." },
  { week: 12, topic: "Decision Making", topicIcon: "<i data-lucide='dice-5'></i>", q: "Expected Utility Theory (Normative)",
    expl: "A 'Normative/Prescriptive' model of how rational choices SHOULD be made: calculating the absolute utility of an option multiplied by its objective probability of occurrence." },
  { week: 12, topic: "Decision Making", topicIcon: "<i data-lucide='dice-5'></i>", q: "Preference Reversal",
    expl: "A violation of Expected Utility Theory where human preference between option A and B flips when simply placed into a different scenario. Proves humans are structurally irrational." },
  { week: 12, topic: "Decision Making", topicIcon: "<i data-lucide='dice-5'></i>", q: "Prospect Theory (Descriptive)",
    expl: "Kahneman & Tversky's model detailing how humans ACTUALLY evaluate options. Decisions are based purely on the subjective gain/loss from an immediate reference point, not the absolute end value." },
  { week: 12, topic: "Decision Making", topicIcon: "<i data-lucide='dice-5'></i>", q: "Loss Aversion",
    expl: "A tenet of Prospect Theory stating that humans feel losses far more acutely than equivalent gains. The psychological pain of losing $50 is vastly greater than the pleasure of gaining $50." },
  { week: 12, topic: "Decision Making", topicIcon: "<i data-lucide='dice-5'></i>", q: "Framing Effects in Choice",
    expl: "Human choices completely reverse depending on presentation. If framed in terms of 'Gaining', people avoid risk (seek the sure bet). If framed as 'Losing', people take wild risks to avoid the loss." },
  { week: 12, topic: "Decision Making", topicIcon: "<i data-lucide='dice-5'></i>", q: "Psychological Accounting",
    expl: "The irrational assignment of mental separate accounts to values. Losing a $10 ticket makes a human refuse to buy a new one, but losing a $10 bill will not stop them from buying the exact same ticket." },
  { week: 12, topic: "Decision Making", topicIcon: "<i data-lucide='dice-5'></i>", q: "Sunk Cost Fallacy",
    expl: "An extension of Psychological Accounting where humans irrationally throw perfectly good resources/money into an unrewarding, failing option purely because they have already invested in it." },
  { week: 12, topic: "Decision Making", topicIcon: "<i data-lucide='dice-5'></i>", q: "Role of Affect (Deliberative vs Affective)",
    expl: "In Deliberative mode, people mathematically calculate value based on 'scope' (e.g. saving 4 tigers > 1 tiger). In Affective mode, decisions are purely feeling-based, meaning scope becomes entirely irrelevant." }
];

// Append the unified property for rendering in quiz.html correctly
STUDY_MATERIALS.forEach(sm => {
  sm.isSupplementary = true;
});
